import{_ as a,o,c as t,a3 as l}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"133. Catt On Call Recall Allowances","description":"","frontmatter":{"title":"133. Catt On Call Recall Allowances","eba":"Mental Health Services 2024-2028","topics":["leave","public-holidays","allowances"]},"headers":[],"relativePath":"ebas/mental-health/health-professionals/hours-of-work/133-catt-on-call-recall-allowances.md","filePath":"ebas/mental-health/health-professionals/hours-of-work/133-catt-on-call-recall-allowances.md"}'),r={name:"ebas/mental-health/health-professionals/hours-of-work/133-catt-on-call-recall-allowances.md"};function n(s,e,i,c,p,h){return o(),t("div",null,[...e[0]||(e[0]=[l('<h1 id="_133-catt-on-call-recall-allowances" tabindex="-1">133. Catt On Call Recall Allowances <a class="header-anchor" href="#_133-catt-on-call-recall-allowances" aria-label="Permalink to &quot;133. Catt On Call Recall Allowances&quot;">​</a></h1><p><strong>133.1</strong> On-call Allowance</p><p><strong>(a)</strong> Employees engaged for on-call/recall for the provision of a crisis response (CATT- type function), shall be paid an allowance at the rate set out in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> for each on call period of 12 hours or part thereof commencing with the following rates:</p><p><strong>(i)</strong> Monday to Friday – as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(ii)</strong> Saturday - as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(iii)</strong> Sunday or public holiday - as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(iv)</strong> Weekend public holiday - as per <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>.</p><p><strong>(b)</strong> The telephone allowance in the 2020 Agreement does not apply from FFPPOA 20 May 2025 and has been included in the rates at 133.1(a) above.</p><p><strong>(c)</strong> An Employee rostered to be on-call for a period spanning two days over which two different on-call allowances apply will receive a payment which is equal to the allowance payable for the day attracting the higher allowance.</p><p><strong>(d)</strong> The purpose of the allowance set out in this clause is to compensate Employees for the inconveniences associated with being on-call and performing duty of up to one hour.</p><p><strong>133.2</strong> Recall</p><p><strong>(a)</strong> The on-call allowance includes payment of work performed of up to one hour&#39;s aggregate duration for each on-call period.</p><p><strong>(b)</strong> For work performed in excess of an aggregate of one hour during an on-call period, payment shall be made at the normal overtime rate paid at the Employee&#39;s substantive classification and increment level.</p><p><strong>(c)</strong> The parties are to regard telephone attendance as recall to duty.</p><p><strong>133.3</strong> Additional Provisions</p><p><strong>(a)</strong> Only one Employee per team each night shall be rostered on-call and in receipt of the allowance. No other team member (other than a psychiatrist) will be required or requested to provide out of hours service for that particular night.</p><p><strong>(b)</strong> Employees are to receive an uninterrupted break of at least 10 hours between the end of the recall and the next shift. Where the 10-hour break is not observed double time will be paid for all work performed until such break is observed.</p><p><strong>(c)</strong> An Employer may not require an Employee to be on call for CATT type duties for a period of more than 12 hours.</p><p><strong>(d)</strong> The on-call/recall allowance for CATT type duties applies to all Employees who are required to perform CATT type duties.</p><p><strong>133.4</strong> Savings Provision</p><p><strong>133.5</strong> Despite clause 133.1, existing arrangements for periods of on-call for CATT type duties below 12 hours that existed prior to 29 September 2001 may continue.</p>',21)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
